import React, { useState, useRef, useEffect } from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./TopNavbar.css";

const TopNavbar = () => {
  const navigate = useNavigate();
  const dropdownRef = useRef();

  const [menuOpen, setMenuOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);

  let user = null;
  try {
    user = JSON.parse(localStorage.getItem("user"));
  } catch {
    user = null;
  }

  /* 👆 Close profile dropdown on outside click */
  useEffect(() => {
    const handler = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setProfileOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  return (
    <div className="topbar">
      {/* LEFT */}
      <div className="topbar-left">
        {/* 🍔 HAMBURGER (mobile) */}
        <div
          className={`hamburger ${menuOpen ? "open" : ""}`}
          onClick={() => setMenuOpen(!menuOpen)}
        >
          <span />
          <span />
          <span />
        </div>

        <h3>College Event Portal</h3>
      </div>

      {/* 📱 MOBILE MENU */}
      <div className={`mobile-menu ${menuOpen ? "show" : ""}`}>
        {user?.role === "student" && (
          <>
            <NavLink to="/student/events">Events</NavLink>
            <NavLink to="/student/my-events">My Events</NavLink>
          </>
        )}

        {user?.role === "staff" && (
          <>
            <NavLink to="/staff/dashboard">Dashboard</NavLink>
            <NavLink to="/staff/events">Events</NavLink>
          </>
        )}

        {user?.role === "admin" && (
          <>
            <NavLink to="/admin/dashboard">Dashboard</NavLink>
            <NavLink to="/admin/events">Events</NavLink>
            <NavLink to="/admin/users">Users</NavLink>
          </>
        )}
      </div>

      {/* RIGHT */}
      <div className="profile" ref={dropdownRef}>
        {/* 👤 PROFILE ICON */}
        <div className="avatar" onClick={() => setProfileOpen(!profileOpen)}>
          👤
        </div>

        {profileOpen && (
          <div className="profile-dropdown">
            <p>{user?.name || "User"}</p>
            <button onClick={handleLogout} className="logout">
              Logout
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default TopNavbar;
